CREATE TABLE IF NOT EXISTS ai_studio_prompts (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, agent_id UUID REFERENCES agents(id) ON DELETE SET NULL, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(180) NOT NULL, slug VARCHAR(140) NOT NULL, category VARCHAR(100), status VARCHAR(40) NOT NULL DEFAULT 'draft', current_version_id UUID, description TEXT, tags JSONB NOT NULL DEFAULT '[]'::jsonb, settings JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ, CONSTRAINT uq_ai_studio_prompt_workspace_slug UNIQUE (workspace_id, slug));
CREATE TABLE IF NOT EXISTS ai_studio_prompt_versions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, prompt_id UUID NOT NULL REFERENCES ai_studio_prompts(id) ON DELETE CASCADE, agent_version_id UUID REFERENCES agent_versions(id) ON DELETE SET NULL, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, version_number INTEGER NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'draft', system_prompt TEXT NOT NULL, developer_prompt TEXT, variables JSONB NOT NULL DEFAULT '{}'::jsonb, sections JSONB NOT NULL DEFAULT '[]'::jsonb, guardrails JSONB NOT NULL DEFAULT '{}'::jsonb, dynamic_context JSONB NOT NULL DEFAULT '{}'::jsonb, model_config JSONB NOT NULL DEFAULT '{}'::jsonb, token_estimate INTEGER NOT NULL DEFAULT 0, validation_state JSONB NOT NULL DEFAULT '{}'::jsonb, release_notes TEXT, published_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), CONSTRAINT uq_ai_studio_prompt_version_number UNIQUE (prompt_id, version_number));
CREATE TABLE IF NOT EXISTS ai_studio_prompt_templates (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(180) NOT NULL, category VARCHAR(100) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'active', description TEXT, template_body TEXT NOT NULL, variables JSONB NOT NULL DEFAULT '{}'::jsonb, recommended_guardrails JSONB NOT NULL DEFAULT '{}'::jsonb, metadata_json JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS ai_studio_playground_runs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, prompt_id UUID REFERENCES ai_studio_prompts(id) ON DELETE SET NULL, prompt_version_id UUID REFERENCES ai_studio_prompt_versions(id) ON DELETE SET NULL, agent_id UUID REFERENCES agents(id) ON DELETE SET NULL, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, channel VARCHAR(40) NOT NULL DEFAULT 'text', input_payload JSONB NOT NULL DEFAULT '{}'::jsonb, output_payload JSONB NOT NULL DEFAULT '{}'::jsonb, execution_trace JSONB NOT NULL DEFAULT '{}'::jsonb, status VARCHAR(40) NOT NULL DEFAULT 'completed', latency_ms INTEGER, cost_usd NUMERIC(12,6), created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_studio_simulation_scenarios (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, prompt_id UUID REFERENCES ai_studio_prompts(id) ON DELETE SET NULL, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(180) NOT NULL, scenario_type VARCHAR(80) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'active', persona JSONB NOT NULL DEFAULT '{}'::jsonb, conversation_script JSONB NOT NULL DEFAULT '[]'::jsonb, assertions JSONB NOT NULL DEFAULT '[]'::jsonb, metadata_json JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS ai_studio_evaluation_metrics (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(160) NOT NULL, metric_key VARCHAR(120) NOT NULL, metric_type VARCHAR(80) NOT NULL, scoring_config JSONB NOT NULL DEFAULT '{}'::jsonb, weight NUMERIC(6,3) NOT NULL DEFAULT 1, status VARCHAR(40) NOT NULL DEFAULT 'active', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_studio_evaluation_runs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, prompt_id UUID REFERENCES ai_studio_prompts(id) ON DELETE SET NULL, prompt_version_id UUID REFERENCES ai_studio_prompt_versions(id) ON DELETE SET NULL, scenario_id UUID REFERENCES ai_studio_simulation_scenarios(id) ON DELETE SET NULL, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, status VARCHAR(40) NOT NULL DEFAULT 'queued', score NUMERIC(6,3), metric_results JSONB NOT NULL DEFAULT '{}'::jsonb, regression_summary JSONB NOT NULL DEFAULT '{}'::jsonb, latency_ms INTEGER, cost_usd NUMERIC(12,6), created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_studio_test_suites (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(180) NOT NULL, description TEXT, status VARCHAR(40) NOT NULL DEFAULT 'active', schedule_config JSONB NOT NULL DEFAULT '{}'::jsonb, deployment_gate BOOLEAN NOT NULL DEFAULT false, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS ai_studio_test_cases (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, suite_id UUID NOT NULL REFERENCES ai_studio_test_suites(id) ON DELETE CASCADE, scenario_id UUID REFERENCES ai_studio_simulation_scenarios(id) ON DELETE SET NULL, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(180) NOT NULL, input_payload JSONB NOT NULL DEFAULT '{}'::jsonb, expected_outcomes JSONB NOT NULL DEFAULT '[]'::jsonb, assertions JSONB NOT NULL DEFAULT '[]'::jsonb, status VARCHAR(40) NOT NULL DEFAULT 'active', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_studio_test_runs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, suite_id UUID NOT NULL REFERENCES ai_studio_test_suites(id) ON DELETE CASCADE, prompt_version_id UUID REFERENCES ai_studio_prompt_versions(id) ON DELETE SET NULL, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, status VARCHAR(40) NOT NULL DEFAULT 'queued', total_tests INTEGER NOT NULL DEFAULT 0, passed_tests INTEGER NOT NULL DEFAULT 0, failed_tests INTEGER NOT NULL DEFAULT 0, results JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());CREATE TABLE IF NOT EXISTS ai_studio_benchmarks (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, baseline_prompt_version_id UUID REFERENCES ai_studio_prompt_versions(id) ON DELETE SET NULL, candidate_prompt_version_id UUID REFERENCES ai_studio_prompt_versions(id) ON DELETE SET NULL, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'queued', metrics JSONB NOT NULL DEFAULT '{}'::jsonb, comparison_summary JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_studio_experiments (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, name VARCHAR(180) NOT NULL, experiment_type VARCHAR(80) NOT NULL DEFAULT 'ab_test', status VARCHAR(40) NOT NULL DEFAULT 'draft', variants JSONB NOT NULL DEFAULT '[]'::jsonb, traffic_allocation JSONB NOT NULL DEFAULT '{}'::jsonb, metrics JSONB NOT NULL DEFAULT '{}'::jsonb, guardrails JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), deleted_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS ai_studio_deployments (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, prompt_id UUID NOT NULL REFERENCES ai_studio_prompts(id) ON DELETE CASCADE, prompt_version_id UUID NOT NULL REFERENCES ai_studio_prompt_versions(id) ON DELETE CASCADE, rollback_version_id UUID REFERENCES ai_studio_prompt_versions(id) ON DELETE SET NULL, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, environment VARCHAR(60) NOT NULL DEFAULT 'staging', status VARCHAR(40) NOT NULL DEFAULT 'draft', approval_state JSONB NOT NULL DEFAULT '{}'::jsonb, rollout_config JSONB NOT NULL DEFAULT '{}'::jsonb, deployed_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_studio_comments (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, prompt_id UUID REFERENCES ai_studio_prompts(id) ON DELETE CASCADE, prompt_version_id UUID REFERENCES ai_studio_prompt_versions(id) ON DELETE CASCADE, parent_comment_id UUID REFERENCES ai_studio_comments(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, body TEXT NOT NULL, mentions JSONB NOT NULL DEFAULT '[]'::jsonb, status VARCHAR(40) NOT NULL DEFAULT 'open', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_studio_activity_logs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, entity_type VARCHAR(80) NOT NULL, entity_id UUID, action VARCHAR(120) NOT NULL, summary TEXT, metadata_json JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_studio_analytics_records (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, prompt_id UUID REFERENCES ai_studio_prompts(id) ON DELETE SET NULL, prompt_version_id UUID REFERENCES ai_studio_prompt_versions(id) ON DELETE SET NULL, metric_name VARCHAR(120) NOT NULL, metric_value NUMERIC(14,4) NOT NULL DEFAULT 0, dimensions JSONB NOT NULL DEFAULT '{}'::jsonb, captured_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_studio_interaction_timelines (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, playground_run_id UUID REFERENCES ai_studio_playground_runs(id) ON DELETE CASCADE, conversation_id UUID REFERENCES conversations(id) ON DELETE SET NULL, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, event_type VARCHAR(100) NOT NULL, sequence INTEGER NOT NULL DEFAULT 0, duration_ms INTEGER, payload JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_studio_replay_sessions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, conversation_id UUID REFERENCES conversations(id) ON DELETE SET NULL, voice_session_id UUID REFERENCES voice_sessions(id) ON DELETE SET NULL, prompt_version_id UUID REFERENCES ai_studio_prompt_versions(id) ON DELETE SET NULL, created_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, updated_by_user_id UUID REFERENCES users(id) ON DELETE SET NULL, status VARCHAR(40) NOT NULL DEFAULT 'ready', transcript JSONB NOT NULL DEFAULT '[]'::jsonb, audio_refs JSONB NOT NULL DEFAULT '[]'::jsonb, timeline JSONB NOT NULL DEFAULT '[]'::jsonb, inspection_notes JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS ix_ai_studio_prompts_workspace_status ON ai_studio_prompts(workspace_id, status, deleted_at);
CREATE INDEX IF NOT EXISTS ix_ai_studio_prompt_versions_prompt_status ON ai_studio_prompt_versions(prompt_id, status);
CREATE INDEX IF NOT EXISTS ix_ai_studio_templates_workspace_category ON ai_studio_prompt_templates(workspace_id, category, status);
CREATE INDEX IF NOT EXISTS ix_ai_studio_playground_prompt_created ON ai_studio_playground_runs(prompt_id, created_at);
CREATE INDEX IF NOT EXISTS ix_ai_studio_evaluation_prompt_status ON ai_studio_evaluation_runs(prompt_version_id, status);
CREATE INDEX IF NOT EXISTS ix_ai_studio_test_runs_suite_status ON ai_studio_test_runs(suite_id, status);
CREATE INDEX IF NOT EXISTS ix_ai_studio_deployments_prompt_env ON ai_studio_deployments(prompt_id, environment, status);
CREATE INDEX IF NOT EXISTS ix_ai_studio_activity_entity ON ai_studio_activity_logs(entity_type, entity_id, created_at);
CREATE INDEX IF NOT EXISTS ix_ai_studio_analytics_prompt_metric ON ai_studio_analytics_records(prompt_id, metric_name, captured_at);
CREATE INDEX IF NOT EXISTS ix_ai_studio_timeline_run_sequence ON ai_studio_interaction_timelines(playground_run_id, sequence);